{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        {
          "항목": "릴리스 공개 목표일 확정: 화요일/수요일이 아니라 공개 릴리스 목표는 금요일 15:00 KST(연기 조건: 스모크 테스트 통과)로 확정",
          "근거": "세미나 메모의 핵심 합의"
        },
        {
          "항목": "패키지명(packageName) 불일치 대응은 스크립트에서 단순 무시하지 않음. 우선 패키지 설정/계약을 점검하고, 계약 자체가 잘못된 경우에만 스크립트를 검토",
          "근거": "Hara 제안(무시) 논의 후 합의"
        },
        {
          "항목": "확인된 액션: Minjun이 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유",
          "근거": "확정 액션 항목"
        },
        {
          "항목": "확인된 액션: Doyun이 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
          "근거": "확정 액션 항목"
        },
        {
          "항목": "Hara가 Minjun의 스모크 결과 공유 후 생성된 tarball 경로 점검",
          "근거": "합의된 후속 작업"
        }
      ],
      "rejected": [
        {
          "항목": "Hara의 `smoke-theme-pack.mjs`에서 packageName 불일치 시 강제 무시 처리 제안",
          "근거": "논의 후 거부됨"
        }
      ],
      "stretch_goals": [
        {
          "항목": "수요일 공개 릴리스는 내부 stretch goal로만 유지(최종 공개 목표 아님)",
          "근거": "Seoyeon 제안 대비 Doyun 반대 후 정리"
        }
      ]
    },
    "non-decisions": [
      {
        "항목": "README 설치 단계 검토(목표: 목요일 가능 시)는 제안됨. 소유자 지정/최종 상태 미확정",
        "근거": "Seoyeon 제안"
      },
      {
        "항목": "Hara의 tarball 경로 점검은 기한 미지정",
        "근거": "후속 점검 항목으로만 확정"
      }
    ],
    "risks": [
      {
        "항목": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음",
        "근거": "명시된 리스크"
      },
      {
        "항목": "README 설치 가이드가 오래되면 릴리스 노트 및 사용자 안내가 오도될 수 있음",
        "근거": "명시된 리스크"
      }
    ],
    "open_questions": [
      {
        "항목": "최종 릴리스 승인 권한자는 누구인가?",
        "근거": "회의 중 미해결 질문"
      },
      {
        "항목": "내부 수요일 stretch goal를 릴리스 노트에 기재할지 여부",
        "근거": "결정 미정"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainy": "높음"
    },
    {
      "owner": "Doyun",
